//! Topology-gated residual deblur for structured image fringes.
//!
//! Full-Send Monster Descent Architecture + Arnold Cat Map:
//! Maps the 2D gradient field into the 66-dimensional Aeon space, uses the
//! Arnold Cat Map (mod 5, order 10) to scramble the gradient field (Topological Shuffling),
//! injects the Lucas Sequence as the metric generator for the Discrete Harmonic Sieve,
//! expands it through the 7 Fano planes into the 196884-dimensional Monster space,
//! applies the topological gating, and folds the resolution back down.

use serde::{Deserialize, Serialize};
use std::collections::{HashMap, HashSet};

use crate::depth_extrusion::DepthError;
use crate::e8_quantizer::nearest_e8;
use crate::leech_visual_sieve::{
    leech_visual_feature_from_n_rgb, leech_visual_key, LeechVisualResidentShellCache,
    LeechVisualRoutePayload, LeechVisualShellCachePolicy, LeechVisualSieveConfig,
};
use crate::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
use crate::topology_mask::{build_topology_alpha, RgbLayout, TopologyAlphaConfig};

pub const MESH_RESIDUAL_DEBLUR_VERSION: &str = "mesh_residual_deblur/v6_cat_monster_detail";

/// Which lattice (if any) the residual-lift 8-blocks are quantized onto
/// before reconstruction. Additive + opt-in; the default is [`None`], which
/// leaves the deblur output byte-for-byte unchanged from the legacy path.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum ResidualQuantizer {
    /// No residual quantization. The reconstruction is identical to the
    /// historical `v4_cat_monster` path. (Default.)
    #[default]
    None,
    /// Cubic ℤ⁸ quantization: round each residual sample to the nearest grid
    /// point at the configured step. Worst-case 8-D quantizer (G = 1/12).
    /// Present so the E8 win can be measured at the **same bit budget**.
    Cubic,
    /// E_8 quantization: snap each residual 8-block to the nearest E_8 cell
    /// (`Gnosis.E8Lattice.reflection_closure`). Optimal 8-D quantizer
    /// (G(E8) ≈ 0.0717, ~14% lower MSE than cubic at equal cell density).
    E8,
}

#[derive(Clone, Debug)]
pub struct MeshResidualDeblurConfig {
    pub overpotential: f32,
    pub admission_floor: f32,
    pub saturation_limit: f32,
    pub depth_confidence_blend: f32,
    pub enable_fano_cache_keys: bool,
    pub topology: TopologyAlphaConfig,
    pub depth: MeshDepthConfig,
    /// Opt-in residual quantizer. DEFAULT-OFF value door, mirroring
    /// `amplituhedron.rs::e8_admit_enabled`: when [`ResidualQuantizer::None`]
    /// (default) the reconstruction is byte-for-byte the legacy path. When
    /// [`ResidualQuantizer::E8`] / [`ResidualQuantizer::Cubic`], the per-pixel
    /// residual lift is grouped into 8-sample blocks and snapped to the
    /// chosen lattice before `dst = src + lift`.
    pub residual_quantizer: ResidualQuantizer,
    /// Convenience flag mirroring the task contract / the `e8_admit_enabled`
    /// naming. When `true` it forces `residual_quantizer = E8` unless the
    /// caller already set a non-`None` quantizer explicitly. Default false.
    pub e8_quantize_residual: bool,
    /// Quantization step (cell edge) applied to the residual lift before
    /// lattice snapping, in **lift units**. This sets the shared bit budget:
    /// the residual is divided by the step, quantized on the lattice, then
    /// multiplied back. Smaller step = finer cells = more bits. Cubic and E8
    /// use the SAME step so the comparison is at equal budget. Default 0.02
    /// (the residual lift is O(saturation_limit) ≈ 0.18, so ~9 levels).
    pub residual_quant_step: f32,
    /// Opt-in Leech visual sieve report. DEFAULT-OFF and diagnostic-only: it
    /// computes one 24-D Leech visual key per pixel from the existing
    /// `n_rgb` compass tensor, but never changes reconstructed pixels.
    pub enable_leech_visual_sieve: bool,
    /// Config for the 24-D Leech visual sieve.
    pub leech_visual_sieve: LeechVisualSieveConfig,
    /// Pixel stride for Leech visual diagnostics. `1` samples every pixel;
    /// larger values are for large reconstruction jobs where the Leech shell
    /// scan is intentionally off-hot-path.
    pub leech_visual_stride: usize,
    /// Opt-in resident cache for exact-address Leech shell routes. When enabled,
    /// repeated shell-address hits reuse route payloads and apply route-bucket
    /// admission hints as the effective gate for the pixel.
    pub enable_leech_visual_shell_cache: bool,
    /// Maximum entries retained by the resident Leech shell cache.
    pub leech_visual_shell_cache_max_entries: usize,
    /// Number of downstream route buckets used by resident Leech payloads.
    pub leech_visual_route_bucket_count: u16,
    /// Additive confidence boost applied when a resident route-bucket admission
    /// hint is reused. Bounded to [0, 0.25] at runtime.
    pub leech_visual_route_hint_boost: f32,
    /// Route the resident admission hint by the full 196 560-lane kaiju address
    /// (the Leech minimal vectors, Co₀ = Aut(Leech)) instead of the u16
    /// `route_bucket` (≤65 535, which aliases distinct Leech directions). ~819×
    /// finer directional resolution for the visual sieve / deblur. Set false to
    /// reproduce the legacy u16 bucketing exactly (for A/B measurement).
    pub enable_kaiju_lane_routing: bool,
}

impl Default for MeshResidualDeblurConfig {
    fn default() -> Self {
        Self {
            overpotential: 0.85,
            admission_floor: 0.2,
            saturation_limit: 0.18,
            depth_confidence_blend: 0.5,
            enable_fano_cache_keys: true,
            topology: TopologyAlphaConfig::default(),
            depth: MeshDepthConfig::default(),
            residual_quantizer: ResidualQuantizer::None,
            e8_quantize_residual: false,
            residual_quant_step: 0.02,
            enable_leech_visual_sieve: false,
            leech_visual_sieve: LeechVisualSieveConfig::default(),
            leech_visual_stride: 1,
            enable_leech_visual_shell_cache: false,
            leech_visual_shell_cache_max_entries: 256,
            leech_visual_route_bucket_count: 256,
            leech_visual_route_hint_boost: 0.02,
            enable_kaiju_lane_routing: true,
        }
    }
}

impl MeshResidualDeblurConfig {
    /// Resolve the effective quantizer, honoring the `e8_quantize_residual`
    /// convenience flag (it only upgrades `None`, never overrides an explicit
    /// choice).
    fn effective_quantizer(&self) -> ResidualQuantizer {
        match self.residual_quantizer {
            ResidualQuantizer::None if self.e8_quantize_residual => ResidualQuantizer::E8,
            other => other,
        }
    }
}

fn gaussian5_channel(rgb: &[f32], w: usize, h: usize, x: usize, y: usize, c: usize) -> f32 {
    const K: [f32; 5] = [1.0, 4.0, 6.0, 4.0, 1.0];
    let mut acc = 0.0_f32;
    for ky in 0..5 {
        let yy = (y as i32 + ky as i32 - 2).clamp(0, h as i32 - 1) as usize;
        for kx in 0..5 {
            let xx = (x as i32 + kx as i32 - 2).clamp(0, w as i32 - 1) as usize;
            acc += rgb[(yy * w + xx) * 3 + c] * K[ky] * K[kx];
        }
    }
    acc / 256.0
}

fn box9_channel(rgb: &[f32], w: usize, h: usize, x: usize, y: usize, c: usize) -> f32 {
    let mut acc = 0.0_f32;
    for ky in 0..9 {
        let yy = (y as i32 + ky - 4).clamp(0, h as i32 - 1) as usize;
        for kx in 0..9 {
            let xx = (x as i32 + kx - 4).clamp(0, w as i32 - 1) as usize;
            acc += rgb[(yy * w + xx) * 3 + c];
        }
    }
    acc / 81.0
}

